using namespace std;

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            cin >> a[i];
        }

        int presses = 0;
        int state = 0; 

        for (int i = 0; i < n; ++i) {
            if (a[i] == state) {
                presses++;
                state = 1 - state;
            }
        }
        cout << presses << endl;
    }
    return 0;
}

