import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();

        while (t-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }

            int presses = 0;
            int state = 0;

            for (int i = 0; i < n; i++) {
                if (a[i] == state) {
                    presses++;
                    state = 1 - state;
                }
            }
            System.out.println(presses);
        }
        sc.close();
    }
}

